-----------------------------------------------------------------
function LBlockMiniGameBaseCtrl:LBlockMiniGameBaseCtrl(mgr, map)
	self._mgr = mgr
	self._map = map

	---@type LxBehaviour
	self._behaviour = LxBehaviour:New()
end

function LBlockMiniGameBaseCtrl:Destroy()
	if self._behaviour then
		self._behaviour:Dispose()
	end
	self:OnDestroy()
end

function LBlockMiniGameBaseCtrl:GetMgr()
	return self._mgr
end

function LBlockMiniGameBaseCtrl:GetMap()
	return self._map
end

function LBlockMiniGameBaseCtrl:GetTime()
	return Time.time
end

function LBlockMiniGameBaseCtrl:EventRemoveAll()
	local register = self._behaviour
	if (register) then
		register:RemoveEventHandlerList()
	end
end

function LBlockMiniGameBaseCtrl:EventRecv(event,  func, target)
	local register = self._behaviour
	if register then
		register:AddEventHandler(event, func, target)
	end
end

function LBlockMiniGameBaseCtrl:EventRemove(event)
	local register = self._behaviour
	if register then
		register:RemoveEventHandler(event)
	end
end

